var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"악마와 마주쳤다고?","JPN":"悪魔と遭遇したって？","ENG":"You met a devil?","TWN":"你說你們遇到魔鬼？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"호박머리를 달고 있는 괴상한 악마였어.","JPN":"カボチャの頭をした、奇怪な悪魔だったよ。","ENG":"He was an odd devil with a pumpkin for a head.","TWN":"是個有著南瓜頭的奇怪魔鬼。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그 녀석, 우리를 마치 기다렸다는 듯 나타났다고.","JPN":"あいつはまるで、あたしたちが来るのを待っていたかのように現れたの。","ENG":"It was as if he was waiting for us.","TWN":"那傢伙是早有準備，在等我們出現。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"하지만 무사히 돌아온 걸 보니, 루를 함께 보내길 잘 한 모양이네.","JPN":"でも無事に帰ってこれたんだから、やはりルーを一緒に行かせてよかったみたいね。","ENG":"But seeing how you two are back safe, it was a wise choice to send Lugh along.","TWN":"不過既然你們能夠平安回來，看來帶上露是個明智的決定。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐어, 부정하진 않을게. 조금 도움이 되긴 했으니까.","JPN":"まぁ、否定はしないよ。ちょっとは役に立ったから。","ENG":"Well, I won't deny it. She did help a little.","TWN":"嗯，我不否認，確實有點幫助。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"조금만 도움이 된 건가요?","JPN":"ちょっとだけなんですか？","ENG":"Just a little?","TWN":"只是有點幫助嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"조금…","JPN":"それは……","ENG":"A little...","TWN":"有…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아주 많이… 도움이 됐어! 됐지?","JPN":"すごくたくさん……役に立ったわよ！　それでいい？","ENG":"more... than just a helping hand! Happy?","TWN":"非常…大的幫助！可以了吧！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네! 고마워요.","JPN":"はい、ありがとうございます。","ENG":"Yes! Thank you.","TWN":"謝謝你。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어쨌든 이번 원정은 실패야.","JPN":"とにかく、今回の遠征は失敗よ。","ENG":"Anyway, this expedition was a bust.","TWN":"總之就結果而言，這次的遠征是失敗的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"구해온 적철도 계획보다 부족하고, 선발대와 관련된 흔적은 찾지도 못했으니까.","JPN":"入手した赤鉄も計画より少ないし、先発隊に関する痕跡は何一つ見つけられなかったからね。","ENG":"The amount of Violarite we brought was less than what we planned, and we couldn't find any clues related to the advance party.","TWN":"帶回來的赤鐵比預期的還要少，而且也沒找到先遣隊的任何蹤跡。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"흔적도 없었다라…","JPN":"何も痕跡がなかった……か。","ENG":"There wasn't even a trace...","TWN":"連蹤跡都沒有…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"어쩌면 너희가 해치웠다는 호박머리 괴물들이 선발대와 연관이 있는 게 아닐까?","JPN":"もしかしたら、アナタたちが追い払ったというカボチャ頭の化け物が、先発隊の失踪と何か関連があるのかもしれないわね。","ENG":"Perhaps those pumpkin-head monsters you defeated have some correlation?","TWN":"你們打倒的那些南瓜頭怪物，會不會和先遣隊有什麼關聯？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"えっ……？","ENG":"What...?","TWN":"什麼意思…？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그렇다는 건… 설마 그 악마를 따르는 괴물들이 20년 전의 조사단 사람들이란 건가요?","JPN":"それって……まさかあの悪魔に従っていた化け物たちが、20年前の調査隊の方々ということなんですか？","ENG":"Are you saying... that those monsters following that devil are the survey corps from twenty years ago?","TWN":"你是想說…那些跟隨魔鬼的怪物，是20年前的調查團成員？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐라는 거야! 끔찍한 소리 하지 마!","JPN":"なに言ってるのよ！　とんでもないことを言わないで！","ENG":"Are you kidding me?! Don't say something that terrible!","TWN":"你在說什麼！少說嚇人的話！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"죄, 죄송해요! 너무 멋대로 짚었나?","JPN":"す、すみません。行き過ぎた憶測でした。","ENG":"I-I'm sorry! Did my imagination go too far?","TWN":"對…對不起！是我太天馬行空？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"하지만 귀염둥이. 너도 배워서 알고 있잖니?","JPN":"でも可愛子ちゃん。アナタもそう習ったでしょう？","ENG":"But cutie, you were also taught, so you know.","TWN":"但是小可愛，你也學過這些，不是嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"악마는 인간의 영혼을 갈취하고 계약을 통해 자신의 하수인으로 부린다는 걸 말이야.","JPN":"悪魔は人の魂を喰らい、契約によって自分のしもべにしてしまうと。","ENG":"A devil extorts human souls and makes them his servants through contracts.","TWN":"魔鬼會掠奪人類的靈魂，藉由契約將人類變成自己的僕人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그게 사실이라면, 주민들에겐 말하지 않는 게 좋겠어.","JPN":"もしそれが本当なら、住民たちには言わない方がいいね。","ENG":"If that's true, I think it's best not to tell the villagers.","TWN":"如果那是真的，那最好不要告訴村民。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"자기 가족이 괴물이 됐다는 소식을 기다리던 사람은 없을 테니까.","JPN":"自分の家族が化け物になったなんて聞きたくないはずだから。","ENG":"No one will want to hear that their loved ones have turned into monsters.","TWN":"沒有人會想聽到自己家人變成怪物的消息。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그래. 그런 진실이라면, 차라리 모르는 편이 나을지도 모르겠네.","JPN":"そうね。それが本当なら、知らない方がいいかもしれないわね。","ENG":"Yes. If that is the truth, it is best not to know.","TWN":"沒錯，如果若真相是如此，倒不如不要知道。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그래도, 너희가 무사히 돌아와서 다행이야.","JPN":"でも、アナタたちが無事帰ってきてくれて、本当によかったわ。","ENG":"Nevertheless, I am glad you are back safe.","TWN":"不過，至少這次大家都平安回來。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"실패를 만회할 기회는 다음에도 있으니까.","JPN":"失敗を挽回するチャンスは次回もあるしね。","ENG":"There are still more opportunities to make up for failure.","TWN":"下次還有機會彌補失敗。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저기… 실례지만, 그루터기에 이런 무기를 고쳐 주시는 분도 있을까요?","JPN":"あの……すみません。切り株にこういった武器を直せる方っていらっしゃいますか？","ENG":"Um... I'm sorry to interrupt, but is there someone who can repair this weapon in the Stump?","TWN":"那個…打斷一下，這裡有人能修理我的武器嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"어머, 원정 도중에 고장 난 거니?","JPN":"あら、遠征中に壊れちゃったの？","ENG":"Oh, my. Did it break during the expedition?","TWN":"哎呀，是在遠征途中壞掉的嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"모르가나에게 부탁하면 금방 해결해줬을 텐데.","JPN":"モルガナにお願いすれば、すぐに直してくれるわよ。","ENG":"Morgana would have fixed it in minutes if you had asked her.","TWN":"如果拜託莫甘娜，她應該很快就能幫你修好。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네? 모르가나가 그런 것도 할 수 있나요?","JPN":"はい？　モルガナはそんなこともできるんですか？","ENG":"Huh? Morgana can do that too?","TWN":"真的嗎？莫甘娜還會修東西喔？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"당연히 가능하지! 날 뭘로 보는 거야?","JPN":"もちろんできるわよ！　あたしをなんだと思ってんのよ？","ENG":"Of course, I can! Who do you think I am?","TWN":"當然會！你以為我是誰？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"음… 힘이 엄청나게 센 여자아이?","JPN":"うーん……怪力女の子？","ENG":"Um... A really strong girl?","TWN":"呃…力大如牛的女生？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"흥, 물건 고치는 실력은 그루터기에서 내가 멀린 다음이거든?","JPN":"ふん、修理の腕は切り株の中で、あたしがマーリンに次に上手だからね。","ENG":"Hmph! My fixing skills are second to Merlin in the Stump!","TWN":"哼，要說到修理東西，我的技術可是這裡數一數二的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"괜찮을까요? 모르가나에겐 낯선 물건일 텐데.","JPN":"大丈夫でしょうか？　モルガナには馴染みのない武器だと思うんですけど。","ENG":"Can you really fix it? It might be foreign to you.","TWN":"沒問題吧？莫甘娜應該也是第一次看到這種武器吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"상관없어. 이 세계 대부분의 기술은 아발론이 그 근간이니까.","JPN":"関係ないよ。この世界のほとんどの技術はアバロンが基礎となっているから。","ENG":"It doesn't matter. Almost all technology uses Avalon's as its foundation.","TWN":"無所謂，這個世界的大部分技術都是都是源於阿瓦隆。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그 무기의 작동방식도 아발론 기수들이 사용하던 청동가지와 크게 다르지 않을 거야.","JPN":"その武器が動く仕組みも、アバロンの騎手が使用していた青銅の枝とそんなに変わらないはずよ。","ENG":"That weapon's mechanism isn't much different from the Bronze Branch the Avalon knights used.","TWN":"你那個武器的運作方式，和阿瓦隆騎士使用的青銅枝大同小異。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이리 내.","JPN":"ちょっと出してみて。","ENG":"Give it here.","TWN":"拿來。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아… 네, 잘 부탁드려요.","JPN":"あっ……はい！　よろしくお願いします。","ENG":"Oh... okay. Here you go.","TWN":"喔…那就拜託你囉！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그래서, 악마를 상대해본 소감은 어땠어?","JPN":"それで、悪魔と戦ってみた感想はどう？","ENG":"So, what is your impression of fighting a devil?","TWN":"怎麼樣？和魔鬼交手後的感想如何？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이상했어요. 말이 통하는 마물 같았죠.","JPN":"言葉が通じる魔物のようで奇妙でした。","ENG":"It was weird. It was like a monster that could talk to us.","TWN":"很奇怪，那個怪物可以用語言交流。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아니… 말이 통했다기 보단, 거의 자기가 하고 싶은 말만 하는 쪽에 가까웠던 것 같기도…","JPN":"いえ……会話をしたというよりは、相手が一方的に話していたという感じでした……","ENG":"Well... it wasn't really a conversation, but more of him just saying what he wanted to say...","TWN":"不對…與其說是語言，更像是他在自言自語…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"악마라는 건 원래 그래.","JPN":"悪魔とはそういうものよ。","ENG":"Devils are like that.","TWN":"魔鬼就是這樣。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"악마가 언어를 사용하는 이유는 단 하나,","JPN":"悪魔が言葉を話す理由はただ一つ。","ENG":"There is only one reason why devils use language.","TWN":"魔鬼使用語言只有一個原因，"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"남을 속이고 이용하기 위해서일 뿐이니까.","JPN":"人を騙し、利用するためよ。","ENG":"It is to cheat and take advantage of others.","TWN":"就是要欺騙和利用人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아, 그래도 모르가나가 그 악마에게 한 방 먹이긴 했어요.","JPN":"あ、でもモルガナがその悪魔に一発食らわせましたよ。","ENG":"Oh, but Morgana succeeded in shooting that devil.","TWN":"那個，不過莫甘娜有給那個魔鬼扎實的一擊。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그걸 맞고 감쪽같이 사라졌으니, 어쩌면 악마를 해치운 걸지도 몰라요.","JPN":"その後、突然消えたので、もしかしたら悪魔を倒したのかもしれません。","ENG":"Since he disappeared without a trace afterward, maybe the devil was defeated.","TWN":"它被擊中後消失得無影無蹤，莫甘娜應該有打死它吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아니. 죽지 않았어.","JPN":"いいえ、倒してないわ。","ENG":"No, he isn't dead.","TWN":"不，它沒死。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그 녀석이 모습을 감춘 뒤에도, 계속 시선이 느껴졌으니까.","JPN":"あいつの姿が見えなくなった後も、ずっと視線を感じたもの。","ENG":"Because after he disappeared, I could still feel his gaze.","TWN":"它消失後，我還是能感受到它的視線。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"귀염둥이의 말이 맞아.","JPN":"可愛子ちゃんのいう通りよ。","ENG":"Cutie is right.","TWN":"小可愛說得對。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"악마라는 건 영혼을 잃고 집착만 남은 껍데기지만, 한때는 요정이었던 존재거든.","JPN":"悪魔というのは、魂を失い、執念だけが残ってしまった抜け殻のような存在だけど、かつては妖精だったのよ。","ENG":"Devils may be shells, devoid of souls, but they were once fairies.","TWN":"魔鬼雖然是失去靈魂只剩下執念的空殼，但它們曾經是精靈。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그렇게 쉽게 죽을 리 없지.","JPN":"そう簡単には死なないわ。","ENG":"He would not perish so easily.","TWN":"不可能那麼容易就死掉。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네…?","JPN":"はい……？","ENG":"Excuse me...?","TWN":"什麼…？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"악마가 원래는 요정이었다고요?","JPN":"悪魔が元々妖精だったって言うんですか？","ENG":"Devils were once fairies?","TWN":"魔鬼原本…是精靈？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그래.","JPN":"そう。","ENG":"Correct.","TWN":"對。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"역병에 물들어 영혼이 타락한 요정은 악마가 되는 거야.","JPN":"疫病に感染し、魂が墜ちてしまった妖精は悪魔となる。","ENG":"Fairies tainted by the plague become devils.","TWN":"精靈被瘟疫侵蝕後墮落成魔鬼。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_SERIOUS"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그리고 황금나무의 가능성을 대신해, 인간의 가능성을 <color=#ffd34c>양분</color>으로 삼게 되지.","JPN":"そして黄金の木から受け取っていた可能性の代わりとして、人間の可能性を<color=#ffd34c>養分</color>とするようになるのよ。","ENG":"Thus, instead of the Golden Tree's possibilities, they use humans' possibilities as their <color=#ffd34c>nutrition</color>.","TWN":"它們不再以黃金樹的可能性為<color=#ffd34c>養分</color>，轉而以人類的可能性為食。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"우리가 <color=#ffd34c>영혼</color>이라고 부르는 것들 말이야.","JPN":"それは、アタシたちが<color=#ffd34c>魂</color>と呼んでいるものよ。","ENG":"Or what we call, the <color=#ffd34c>soul</color>.","TWN":"也就是我們稱之為<color=#ffd34c>靈魂</color>的東西。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"처음 알았어요.","JPN":"そうだとは知りませんでした。","ENG":"I didn't know that.","TWN":"原來是這樣…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"역사서에도, 동화책에서도, 소원을 들어주는 아발론의 일곱 요정에 대한 언급은 있었지만…","JPN":"歴史書やおとぎ話には、願いを叶えてくれるアバロンの七人の妖精についての記述はあっても……","ENG":"In history books and tales, there were only mentions of the seven wish-granting fairies from Avalon...","TWN":"無論是歷史書或童話書中，都有提到阿瓦隆有的七個可以實現願望的精靈…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그 행방을 찾는 건 엘리시온에서 금기였거든요.","JPN":"その行方を探す行為は、エリシオンでは禁忌とされているんです。","ENG":"but searching for their whereabouts was forbidden in Elysion.","TWN":"但在艾利森，卻禁止我們尋找精靈的下落。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"어쩌면, 교단은 그 사실을 알고 있었던 걸까요?","JPN":"ひょっとすると、教団はその事実を知っていたのかもしれませんね。","ENG":"Do you think the Order knew about this?","TWN":"或許，教團早就知道這個事實吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"알고 있더라도 굳이 그런 사실을 퍼트리진 않았을 거야.","JPN":"仮にそうだとしても、それを公表するようなことはしなかったと思うわ。","ENG":"Even if they did, they would not have let the public know.","TWN":"就算真的知道，他們也不會刻意讓事實散布出去。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"조금이라도 더 많은 희망이 필요한 시기에, 소원을 들어주는 요정의 존재를 부정하려는 인간은 없을 테니까.","JPN":"儚い希望でさえすがりつきたいこの時代において、願いを叶えてくれる妖精の存在を否定するような人間はいないからね。","ENG":"In a time when hope is needed most, there would be no human who would deny the existence of fairies.","TWN":"因為在這個需要更多希望的時代，大家都希望精靈是真實存在的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그럼 이 세계의 요정들은… 전부 악마가 된 걸까요?","JPN":"じゃあ、この世界の妖精はすべて……悪魔となってしまったのでしょうか？","ENG":"Then, are all the fairies of this world... now devils?","TWN":"所以這個世界的精靈…全都變成魔鬼了嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"글쎄. 나도 모든 진실을 알고 있진 않아.","JPN":"さあね。アタシだってすべての真実を知っているわけではないわ。","ENG":"Who knows? I, too, do not know all the truths of this world.","TWN":"這個嘛，其實我也不清楚。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"어쩌면, 아직도 <color=#ffd34c>악마가 되지 않은 요정</color>이 남아있을지도 모르지.","JPN":"もしかすると、まだ<color=#ffd34c>悪魔化していない妖精</color>が残っているかもしれない。","ENG":"Perhaps there is still <color=#ffd34c>a fairy who has not turned into a devil</color> out there.","TWN":"或許，還有<color=#ffd34c>尚未變成魔鬼的精靈</color>。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"하지만 이건 알아두렴.","JPN":"ただ、これだけは心に留めておいて。","ENG":"But know this.","TWN":"但有件事你要記得，"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"내가 알던 <color=#ffd34c>요정을 찾는 순례자</color>들은 모두 끝이 좋지 않았다는 걸.","JPN":"アタシが知る<color=#ffd34c>妖精を追い求めた巡礼者</color>は、いずれもよくない結末を迎えていたということを。","ENG":"All the <color=#ffd34c>pilgrims who sought fairies</color> I know of had met bitter ends.","TWN":"就我知道的，那些曾經去<color=#ffd34c>尋找精靈的朝聖者</color>，下場都不太好。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그렇다고 해도, 전 요정을 찾아야만 해요.","JPN":"仮にそうだとしても、私はやはり探し続けなければなりません。","ENG":"Even if that's the case, I must find one.","TWN":"就算是這樣，我也必須找到精靈。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"…그래.","JPN":"……そう。","ENG":"...Surely.","TWN":"…好吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"하지만 너무 무리하지는 마.","JPN":"あまり無理だけはしないで。","ENG":"But do not overstrain yourself.","TWN":"不過我勸你別太勉強自己。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"난 네가 이곳에서 좀 더 많은 도움을 줬으면 하거든.","JPN":"アタシはここで、アナタの力をもう少し貸りたいと思っているわ。","ENG":"I would like you to be of more help here.","TWN":"畢竟我還希望你能在這裡多幫點忙呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"노력해볼게요.","JPN":"できるだけそうします。","ENG":"I'll try.","TWN":"我會盡力的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"자, 다 고쳤어.","JPN":"はい、直ったわよ。","ENG":"Okay. All fixed.","TWN":"好了，修好了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네? 벌써요?","JPN":"え？　もうですか？","ENG":"What? Already?","TWN":"真的假的？這麼快？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"보강재를 덧댔으니, 앞으론 식물 뿌리에 파먹히는 일은 없을 거야.","JPN":"補強材をあてておいたから、これからは植物の根に浸食されて故障するなんてことはないはずよ。","ENG":"I added some reinforcements, so plant roots won't be able to jam it anymore.","TWN":"我有幫你加一些補強的東西，以後就不會被植物根侵蝕了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그렇게까지… 고마워요.","JPN":"そこまで気を使って……ありがとうございます。","ENG":"That's impressive... Thank you.","TWN":"真的…很謝謝你。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나는 정말 유능한 드루이드네요.","JPN":"モルガナは本当に有能なドロイドですね。","ENG":"You are a competent Druid, Morgana.","TWN":"莫甘娜真是個能幹的德露伊。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아직 견습 길잡이야. 드루이드라 불리는 건 그루터기 최고의 길잡이 한 명뿐이니까.","JPN":"あたしはまだ見習いの導き手よ。ドロイドと呼ばれるべきは切り株の最高の導き手、ただ一人だけなんだから。","ENG":"I'm still just an apprentice pathfinder. Only the best pathfinder in the Stump can be called a Druid.","TWN":"我還只是個實習引路人，只有木墩最棒的引路人才能被稱為德露伊。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그나저나, 왜 그렇게까지 요정에 집착해?","JPN":"それより、どうしてそこまで妖精にこだわるわけ？","ENG":"Anyway, why are you so obsessed with fairies?","TWN":"但是，你為什麼要這麼執著於精靈？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"혼자 동토를 떠돌다 얼어 죽을 뻔했던 일은 벌써 잊은 거야?","JPN":"一人で凍土を彷徨ったあげく、凍死しかけたことをもう忘れたの？","ENG":"Did you forget that you almost froze to death wandering the gelid lands?","TWN":"你這麼快就忘了你自己在凍土徘徊，結果差點凍死嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그건…","JPN":"それは……","ENG":"That's...","TWN":"我…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"어떻게 해서든 이루고 싶은 맹세가 있거든요.","JPN":"なんとしてでも叶えたい誓いがあるんです。","ENG":"because there is an oath I'd like to fulfill.","TWN":"因為我有一個無論如何都想實現的誓言。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그 맹세를 위해, 저는 요정을 만나야만 해요.","JPN":"私はそのために、妖精に会いに行かなければなりません。","ENG":"And for that oath, I must meet a fairy.","TWN":"為了那個誓言，我必須找到精靈。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"죽으면 맹세 같은 게 무슨 소용이야?","JPN":"死んだら誓いも何もかも無意味になっちゃうわよ。","ENG":"Oaths will mean nothing if you die. You know that, right?","TWN":"如果人死了，誓言還有什麼用？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"게다가…","JPN":"それに……","ENG":"Also...","TWN":"而且…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"언니는 더 이상 엘리시온 사람도 아니잖아.","JPN":"お姉さんはもうエリシオンの人間でもないわけでしょ。","ENG":"You're not an Elysion anymore either, Ms. Lugh.","TWN":"姊姊已經不是艾利森的人了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이제 와서 그런 맹세쯤, 눈 감고 무시해도 아무도 탓하지 않을 거라고.","JPN":"今更そんな誓いなんか、知らないふりして目を逸らしたって、誰にも責められたりはしないわよ。","ENG":"So, no one would blame you even if you ignored that oath.","TWN":"就算你裝作不知道，也沒有人會怪你的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나에게 이해를 바라진 않을게요.","JPN":"モルガナにわかってほしいとは言いません。","ENG":"I don't expect you to understand, Morgana.","TWN":"我不奢望莫甘娜能夠理解。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이건 저에게 주어진 시련이니까.","JPN":"これは自分に与えられた試練ですから。","ENG":"But this is an ordeal given to me.","TWN":"但這是我必須承受的考驗。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐야. 기껏 물건도 고쳐줬는데 혼자 가버리다니.","JPN":"何なの。せっかく武器も直してあげたのに、一人でどっか行っちゃうなんて。","ENG":"Huh? I just fixed her stuff and she's walking away alone?","TWN":"搞什麼？人家這麼辛苦幫她修理東西，結果她居然給我一個人跑掉？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"어머, 벌써 혼자 보내기 싫을 정도로 친해진 거니?","JPN":"あら、もう離れるのが寂しいくらい仲良くなったのね？","ENG":"Oh, my. Have you two gotten that close that you do not wish to be a second apart from each other?","TWN":"哎呀，你們二個已經熟到不想分開啦？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그런 거 아니거든?","JPN":"そんなんじゃないわよ！","ENG":"As if!","TWN":"才不是！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어찌됐든 우리 조사단의 일원이 됐으니, 단원으로서 챙겨주는 것뿐이라고.","JPN":"どちらにせよ、もう調査団の一員になったんだし、仲間として気にかけてあげようとしているだけよ。","ENG":"She's a part of the survey corps now and I'm just looking out for her as a member.","TWN":"不管怎樣，既然她是調查團的一員，我作為團長照顧她是應該的！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"걱정되면 따라가보렴.","JPN":"心配なら、追いかけてあげなさい。","ENG":"If you are concerned, please go after her.","TWN":"擔心的話，就跟過去看看吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그루터기의 사람들도 혼자 서성이는 외지인을 그리 달가워하진 않을 테니까.","JPN":"切り株の人たちも、よそ者が一人でうろついているのは、あまり歓迎しないはずよ。","ENG":"Not a lot of the villagers would be thrilled to see an outsider wandering in the Stump by herself.","TWN":"木墩的居民應該也不會喜歡一個獨自外面遊蕩的外地人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"윽, 배고프네요.","JPN":"うっ、お腹が空きましたね。","ENG":"Ngh, I'm so hungry.","TWN":"唔，好餓喔。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_STARVE"},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"나오기 전에 멀린 씨에게 먹을 것 좀 받아갈 걸 그랬나?","JPN":"出る前に、マーリンさんから食べ物を貰っておけばよかったかな。","ENG":"Maybe I should've gotten something to eat from Merlin before taking off.","TWN":"出來前應該跟梅林要點吃的…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"응…?","JPN":"うん……？","ENG":"Hmm...?","TWN":"嗯…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHILDREN_ROOT_NPC_NULL","text":{"KOREA":"…앗, 이쪽을 보고 있어.","JPN":"……あっ、こっちを見たぞ。","ENG":"...Yikes, she's looking over here.","TWN":"…哎呀，她在看我們！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHILDREN_ROOT_NPC_NULL","text":{"KOREA":"어쩌지? 도망칠까?","JPN":"どうする？　逃げた方がいいかな？","ENG":"What should we do? Run?","TWN":"怎麼辦？要逃跑嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"담벼락에 아이들이 숨어있네요. 낯선 복장이라 경계하는 걸까요?","JPN":"塀の後ろに子どもたちが隠れていますね。私の服装は珍しいから警戒しているんでしょうか？","ENG":"The children are hiding at the wall. Are they wary because my clothes are different?","TWN":"牆邊的那些孩子，是因為我的服裝不像本地人，所以在躲著我嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저기. 그렇게 겁먹지 않아도 돼요.","JPN":"あの、そんなに怖がらなくていいですよ。","ENG":"Um, you don't have to be afraid of me.","TWN":"小朋友，不用害怕。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그리고 괜찮다면 식당이 어디에 있는지 가르쳐줄래요?","JPN":"あと、もしよかったら、食事ができる場所を教えてもらえませんか？","ENG":"Also, could you tell me where a restaurant is, if you don't mind?","TWN":"你們可以告訴我，哪裡有吃飯的地方嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHILDREN_ROOT_NPC_NULL","text":{"KOREA":"어쩌지? 말해줘야 하나?","JPN":"どうする？　言ってやるか？","ENG":"What do we do? Should we tell her?","TWN":"怎麼辦？要告訴她嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"다들 뒤로 물러서.","JPN":"みんな、後ろに下がって。","ENG":"Everyone, get behind me.","TWN":"大家都躲我後面。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"으앗? 돌멩이…?","JPN":"うわっ！　石……？","ENG":"Whoa! A rock...?","TWN":"呃？石頭…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"외지인! 당장 그루터기에서 떠나!","JPN":"よそ者！　今すぐに切り株から出ていけ！","ENG":"Outsider! Get out of the Stump, now!","TWN":"外地人！立刻離開木墩！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"떠나라고요? 어디로요?","JPN":"出ていけって、どこにですか？","ENG":"Get out? To where?","TWN":"離開？我要去哪裡？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"너 때문에 우리 엄마가 다쳤어! 걷지도 못하게 됐단 말이야!","JPN":"お前のせいで俺の母さんが怪我したんだ！　歩けなくなっちまったんだぞ！","ENG":"My mom's hurt because of you! She can't even walk anymore!","TWN":"都是你害我媽媽受傷的！她現在根本無法起身走路！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저기, 그건 무슨 오해죠? 전 아무도 다치게 한 적이 없다고요.","JPN":"あの、何か誤解をしていませんか？　私は誰のことも傷つけたりしていません。","ENG":"Um, I think there's been a misunderstanding. I haven't hurt anyone.","TWN":"那個，這是誤會吧？我沒有傷害過任何人。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"네가 그루터기에 마물을 끌어들인 거잖아!","JPN":"お前が魔物を切り株に引き寄せたんだろう！","ENG":"You brought the monsters to the Stump!","TWN":"是你把怪物引到木墩來的！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"네가 오기 전엔 한 번도 이렇게 깊은 곳까지 마물이 쳐들어온 적은 없었다고!","JPN":"お前が来るまでは、一度もこの奥深い村まで魔物が入ってきたことはなかったんだよ！","ENG":"Monsters have never invaded this deep before you came along!","TWN":"在你來之前，怪物從來沒有侵入到這麼裡面的地方！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"마을이 공격받은 게 제 탓이라고요…?","JPN":"村が襲われたのは、私のせいなんですか……？","ENG":"It's my fault that the village was attacked...?","TWN":"村莊受到攻擊…是我的錯…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"말도 안 돼! 무슨 그런 억지가 있어요!","JPN":"そんなのおかしいです！　こじつけないでください！","ENG":"That makes no sense! How could you think that?!","TWN":"胡說！你們在冤枉我！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHILDREN_ROOT_NPC_NULL","text":{"KOREA":"당신, 악마가 보낸 하수인이죠? 우린 다 알고 있어요!","JPN":"あなた、悪魔のしもべでしょ？　俺たちはみんな知っているんだ！","ENG":"We know who you are! You're one of the devil's henchmen, aren't you?","TWN":"大家都知道，你是魔鬼派來的手下！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHILDREN_ROOT_NPC_NULL","text":{"KOREA":"동토 바깥은 이미 오래전에 사람이 살 수 없는 곳이 됐다고 했어요! 그런 곳에서 왔다면 평범한 인간일 리 없잖아요!","JPN":"凍土の外はすでにずっと前から人間の住めない土地となってるって聞いた！　そんなところから来た人間がまともなはずがない！","ENG":"No one can survive for that long out in the gelid lands! And if you're from there, you can't be human!","TWN":"大人說，在凍土之外沒有適合人類居住的地方！那你一定也不是人類！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"무슨 그런 억지가 있나요! 모르는 사람을 무작정 악마 취급하다니…!","JPN":"そんなの屁理屈です！　だからといって他人に対して悪魔呼ばわりするなんて……！","ENG":"What kind of nonsense is that? And how dare you treat someone you don't know as a devil...!","TWN":"胡說八道！怎麼可以隨便把不認識的人當成魔鬼…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그렇다면 그 멀린이란 사람이 악마인 거겠네요! 당신은 그 악마의 숭배자고요!","JPN":"だとしたら、そのマーリンこそ悪魔に違いありませんね！　すると、あなたはその悪魔の崇拝者ということになります！","ENG":"Then that Merlin person must be a devil! And you're her follower!","TWN":"意思就是梅林是魔鬼吧！而你就是魔鬼的信徒！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"呃。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_QM","text":{"KOREA":"야, 꼬맹이들.","JPN":"おい、ガキども。","ENG":"Hey, kids.","TWN":"喂，你們幾個小鬼。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_QM","text":{"KOREA":"지금 뭐하는 거야?","JPN":"いったい何をしているんだ？","ENG":"What do you think you're doing?","TWN":"你們現在在做什麼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHILDREN_ROOT_NPC_NULL","text":{"KOREA":"앗, 조사단 꼬마대장이다.","JPN":"あっ、調査団のガキ大将だ。","ENG":"Eep! It's the little captain of the survey corps.","TWN":"糟糕，是調查團的恰北北團長。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"모르가나…?","JPN":"モルガナ……？","ENG":"Morgana...?","TWN":"莫甘娜…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"너희. 동토에서 왔다고 사람을 악마로 몰아가는 거야?","JPN":"お前ら、凍土から来たというだけで、人を悪魔扱いしているわけ？　　","ENG":"You're not accusing someone from the gelid lands as a devil, are you?","TWN":"你們隨便叫人家魔鬼嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그럼 어디 내 앞에서도 그렇게 말해보시지?","JPN":"じゃあ、あたしにも同じことが言えるよね？","ENG":"If so, then why don't you say it in front of me, huh?","TWN":"敢在我面前再說一遍試試？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"윽…","JPN":"うっ……","ENG":"Ngh...","TWN":"呃…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"마침 이렇게 흉측한 뿔도 달려있겠다. 악마 취급하기 더 편하지 않아?","JPN":"こんな醜いツノもついてるし、悪魔扱いするにはちょうどよくない？","ENG":"I have this ugly horn on my head. So, you can treat me as a devil, right?","TWN":"我頭上還有長醜角呢，怎麼不把我也當成魔鬼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"칫, 가자!","JPN":"ちっ、行くぞ！","ENG":"Tch! Let's leave!","TWN":"嘖，我們走！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHILDREN_ROOT_NPC_NULL","text":{"KOREA":"대장! 같이 가!","JPN":"ちょっと待ってくれ！　隊長！　","ENG":"Boss! Wait up!","TWN":"老大！等等我！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어휴, 저 철부지. 괜히 엄한 사람한테 화풀이나 하고.","JPN":"はぁ、あの小僧。関係ない人に八つ当たりするんじゃないわよ。","ENG":"Ugh, that rascal, taking out his anger on others.","TWN":"哼，臭小孩，又拿別人來出氣。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…괜찮아?","JPN":"……大丈夫？","ENG":"...You okay?","TWN":"…你還好嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네…","JPN":"はい……","ENG":"Yes...","TWN":"還好…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"카롤리스는 그루터기에서도 아주 유명한 악동이야.","JPN":"カロリスは切り株でも悪ガキとしてすごく有名なのよ。","ENG":"Karolis is an infamous punk in the Stump.","TWN":"卡羅黎斯在這裡是有名的小混混。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"당장 그 녀석 집으로 가자. 무릎 꿇리고 사과라도 시켜야겠어.","JPN":"今すぐあいつの家に行こう。跪かせて謝らせるのよ。","ENG":"Let's go to his home and make him kneel and apologize.","TWN":"我們現在就去他家，叫他下跪道歉。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"전 괜찮아요. 정말로요.","JPN":"私は大丈夫ですよ。本当に。","ENG":"I'm okay. Really.","TWN":"我沒關係，真的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"자신이 처한 상황은 좌절스러운데, 낯선 사람을 믿지 못하니 그런 말을 해버린 거겠죠.","JPN":"自分の置かれた状況が絶望的だから、よそ者への不信感であんなことを言ってしまったんだと思うんです。","ENG":"He's just saying it because he's frustrated about his situation, which is why he can't trust strangers.","TWN":"在這樣的大環境下，他也很辛苦吧？而我又是不能信任的陌生人，所以才會說出那種話。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"돌이켜보면 저도… 처음 만난 모르가나를 악마취급 했으니까요.","JPN":"私も……初対面のモルガナに対して悪魔呼ばわりしていましたから。","ENG":"Looking back… I also accused you of being a devil when I first met you, Morgana.","TWN":"現在回想起來…我第一次見到莫甘娜時，也是把你當成魔鬼…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이리 따라와.","JPN":"ついて来て。","ENG":"Follow me.","TWN":"跟我來。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"去哪？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"오라면 오기나 해.","JPN":"いいから、来て。","ENG":"Just follow me, okay?","TWN":"叫你來就來。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"으앗, 잠깐! 어디로 가는데요?","JPN":"わあっ、ちょっと！　どこに行くんですか！？","ENG":"Whoa, hold up! Where are we going?","TWN":"等等！是要去哪？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"와아, 이 골목엔 맛있어 보이는 요리들이 잔뜩 있네요.","JPN":"わあ、この路地には美味しそうな料理がいっぱい並んでいますね。","ENG":"Wow. This alley is full of delicious-looking foods.","TWN":"哇喔，這條巷子裡有好多好吃的。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"기름진 고기, 향긋한 과일 파이…","JPN":"脂がのったお肉、香ばしいフルーツパイ。","ENG":"Juicy and fatty meat, fragrant fruit pies...","TWN":"肥滋滋的肉，香噴噴的水果派…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이런 자극적인 향기를 맡아보는 게 얼마만인지 모르겠어요.","JPN":"こんな刺激的な匂いを嗅ぐのは、なんて久しぶりなんでしょう。","ENG":"I can't remember the last time I smelled something so appetizing.","TWN":"好久沒聞到這麼濃郁的香氣咧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"장터가 항상 이렇게 성대하진 않아. 지금은 땅이 열매를 맺는 수확절이라 나름 풍족하거든.","JPN":"商店が常にこんなに活気があるわけじゃないよ。今は果物の収穫時期だから、食材が豊富なの。","ENG":"The market isn't always as grand as it is now. But it's harvesting season, so we are in abundance.","TWN":"市場平時也沒這麼熱鬧，但現在是豐收季，所以比較豐富一點。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네? 그럼 과일이 자라지 않는 시기도 있는 건가요?","JPN":"え？　じゃあ果物が採れない時期もあるんですか？","ENG":"Huh? Then there are seasons when fruit doesn't grow here?","TWN":"是嗎？所以也會有長不出水果的時候嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그야 당연하잖아. 연중 대부분은 추위 때문에 싹도 자라지 못한다고.","JPN":"そりゃ当然でしょ。一年のほとんどは寒さのせいで芽も生えないんだからね。","ENG":"Of course. It's cold for most of the year which hinders the growth of sprouts.","TWN":"你在說什麼廢話，因為大部分的時候都很寒冷，連芽都發不出來。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"몰랐어요. 엘리시온에선 과일이라면 언제든 구할 수 있었거든요.","JPN":"そうだったんですか。エリシオンでは果物ならいつでも手に入るんですよ。","ENG":"I didn't know. We could always find fruit in Elysion.","TWN":"原來是這樣，因為在艾利森隨時都買得到水果。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"자랑하지 마! 그루터기도 내가 태어나기 전엔 사계절이 멀쩡해서 과일이 아주 풍족했거든?","JPN":"自慢しているの？　切り株だってあたしが生まれる前は四季がちゃんとあったから、果物がたくさん採れてたわよ！","ENG":"Stop bragging! The Stump also had four seasons and had plenty of fruit before I was born too!","TWN":"哼，這是在炫耀嗎！我出生以前氣候也很正常，那時候木墩的水果也是很豐富的！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"}}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"미, 미안해요. 딱히 자랑하려던 건 아니었는데.","JPN":"ご、ごめんなさい。私はそんなつもりじゃ。","ENG":"I-I'm sorry. I didn't mean to brag.","TWN":"抱…抱歉，我沒這個意思。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"}}}},{"id":"L8_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"흥.","JPN":"ふん。","ENG":"Hmph.","TWN":"哼。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아무튼 먹고 싶은 게 있으면 다 먹어.","JPN":"とにかく、今日は食べたいものがあったら、何でも食べていいわよ。","ENG":"Anyway, if there's something you'd like to eat, eat it.","TWN":"總之，想吃什麼就吃吧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"지난 번 빵에 대한 답례니까. 부담은 갖지 말고.","JPN":"こないだのパンのお礼だから、気を遣わなくていいからね。","ENG":"I'm returning the favor for the bread you gave me last time. So don't feel bad.","TWN":"這是上次麵包的回禮，不用客氣。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네! 그럼 사양 않고 잔뜩 먹을게요.","JPN":"はい！　じゃあ遠慮なく、たくさんいただきます！","ENG":"Okay! Then I won't hold back and eat all that I can!","TWN":"好！那我就不客氣囉，我要吃到飽為止！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"중요한 보고가 있다고?","JPN":"大事な報告？","ENG":"You have something important to report?","TWN":"有什麼重要的事嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"네, 127번 화톳불에서 낙원의 기준에 부합하는 좌표를 발견했습니다.","JPN":"はい、127番かがり火で楽園の基準に適合する座標を見つけました。","ENG":"Yes. Coordinates that meet the Promised Land's criteria have been found at the 127th bonfire.","TWN":"是，在第127號篝火發現到符合樂園標準的座標。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"역병 반응과 환경 수준은?","JPN":"疫病反応と環境は？","ENG":"What about the response to the plague and its environmental conditions?","TWN":"瘟疫反應和環境如何？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"역병 반응은 읽히지 않습니다. 환경도 낙원의 7가지 조건에 모두 부합하고요.","JPN":"疫病反応は検知されておりません。環境も楽園の7つの条件すべてを満たしています。","ENG":"There are no readings of plague reactions, and the environment meets all of the seven conditions for the Promised Land.","TWN":"沒有檢測到瘟疫反應，環境也符合樂園的七個條件。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"드디어 찾았구나.","JPN":"やっと見つけたわ。","ENG":"We have finally found it.","TWN":"終於找到了，"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"인류의 다음 터전을 말이야.","JPN":"人類の次なる故郷が。","ENG":"The next habitat for humanity.","TWN":"人類的下一個棲息地。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"하지만 아직 가장 큰 과제가 남아있습니다.","JPN":"しかし、まだ最も大きな課題は残っております。","ENG":"However, the biggest challenge still remains.","TWN":"但還有最重要的任務沒有完成。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"낙원의 관측에 성공했더라도, 저희에겐 아직 그곳에 갈 기술이 없으니까요.","JPN":"楽園の観測には成功しましたが、私たちにはまだそこに行くための技術がありません。","ENG":"Even if we have observed the Promised Land, we still have no means to go there as of now.","TWN":"就算成功找到樂園，我們還沒有前往那裡的技術。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"조급할 필요 없어. 지금까지 해왔던 것처럼만 하면 돼.","JPN":"焦らなくてもいいわよ。今まで通りにやってくれたらいいわ。","ENG":"No need to rush. Just do what we have done so far.","TWN":"不用著急，就照我們一直以來的做法。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"낙원문의 차원도약 기술도 이제 거의 완성 단계니까.","JPN":"楽園の門の次元ワープ技術もほとんど完成に近いんだからね。","ENG":"The space jump technology of Avalon's Gate is in its final stages of competition.","TWN":"而且樂園門的次元跳躍技術也已經趨近完成，"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"조금만 더 노력하면, 그루터기의 모두를 낙원으로 보낼 수 있을 거야.","JPN":"あともう少し頑張れば、切り株のみんなを楽園に連れていくことができるわ。","ENG":"With a little more hard work, we will be able to send everyone at the Stump to the Promised Land.","TWN":"只要再努力一點，就能把所有人都送到樂園了。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"하지만 제사장님…","JPN":"しかし、司祭長……","ENG":"But High Priest...","TWN":"但是祭司長…"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"얼마 전 그루터기에 마물이 습격했습니다.","JPN":"先日、切り株が魔物に襲撃されたのです。","ENG":"The Stump had been attacked by monsters recently.","TWN":"木墩不久前遭到怪物的攻擊。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":" <color=#ffd34c>50년 전의 그날</color>과 같은 일이 또 벌어질지도 모른다며, 다들 불안해하고 있어요.","JPN":" <color=#ffd34c>50年前のあの日</color>と同じことがまた起きるかもしれないと、皆さんの不安が高まっています。","ENG":"Everyone is anxious that another incident like the one <color=#ffd34c>fifty years ago</color> might reoccur.","TWN":"大家都很不安，深怕<color=#ffd34c>50年前的那天</color>會再重演。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"저희에게… 정말 충분한 시간이 있을까요?","JPN":"私たちに……本当に充分な時間が残されているのでしょうか？","ENG":"Do you think... we'll have enough time?","TWN":"我們…真的有足夠的時間嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"종말은 하루하루 가까워지고 있고, 위기는 언제나 존재해왔어.","JPN":"終末は日々近づきつつあり、危機とは常に隣り合わせに生きてきたわ。","ENG":"The end draws near every day, and we have always coexisted with crises.","TWN":"末日一天比一天近，危機一直存在。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"우린 그저 우리가 할 수 있는 최선을 다 하면 돼.","JPN":"ただ自分たちにできることを全力でやるだけよ。","ENG":"We just have to do the best we can.","TWN":"我們只需要盡力而為。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"우리의 선조들이 그래왔던 것처럼.","JPN":"我々の先祖たちと同じように。","ENG":"Like our ancestors had done.","TWN":"就像我們的祖先一樣。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};